Does this correct for the REINFORCE algorithm: \noindent \textbf{Loss}
\begin{align}
    L(\theta)&=-\mathbb{E}_{a \sim \pi_\theta}\left[R(a)\right], \\
    &=-\sum_{a} \pi_\theta(a) R(a).
\end{align}
\noindent \textbf{Gradient}
\begin{align}
\nabla_\theta L(\theta)
&=-\sum_{a} R(a) \nabla_\theta \pi_\theta(a), \\
&=-\sum_{a} R(a) \pi_\theta(a) \nabla_\theta \log \pi_\theta(a), \\
&=-\mathbb{E}_{a \sim \pi_\theta}\left[R(a) \nabla_\theta \log \pi_{\theta}(a) \right].
\end{align}
\noindent \textbf{When the reward $R(a) = 1:$}
\begin{align}
    L(\theta)&=-\sum_{a} \pi_\theta(a),\\
    \nabla_\theta L(\theta)&=-\sum_{a} \pi_\theta(a) \nabla_\theta \log \pi_\theta(a).
\end{align}
